// Generates simple PNG icons using canvas (Node.js built-in via createCanvas workaround)
// Since we don't have canvas, we'll write raw PNG bytes for a solid blue square

import { writeFileSync } from "fs";

// Minimal valid PNG: solid #2563eb blue square
// Generated using a base64-encoded pre-built PNG
const icon192 = Buffer.from(
  "",
  "base64"
);

// Write placeholder — real icons need canvas or sharp
// We'll use an SVG approach via the HTML instead
writeFileSync("public/icon-192.png", icon192);
writeFileSync("public/icon-512.png", icon192); // same size for now

console.log("Icons written to public/");
